from matplotlib import pyplot as pltimport cv2import numpy as npimg = cv2.imread("../data/BSE_Google_noisy.jpg", 1)kernel = np.ones((3,3), np.float32)/9filter_2D = cv2.filter2D(img, -1, kernel)#-1 for ddepth => same data type as the input imgblur = cv2.blur(img, (5,5))gaussian_blur = cv2.GaussianBlur(img, (5,5), 0)median_blur = cv2.medianBlur(img, 3)plt.figure(figsize = (3,4))plt.title("Original")plt.imshow(img)plt.figure(figsize = (3,4))plt.title("Filter2D")plt.imshow(filter_2D)plt.figure(figsize = (3,4))plt.title("Blur")plt.imshow(blur)plt.figure(figsize = (3,4))plt.title("Gaussian Blur")plt.imshow(gaussian_blur)plt.figure(figsize = (3,4))plt.title("Median Blur")plt.imshow(median_blur)